<script setup lang="ts">
import { X, AlertTriangle } from "lucide-vue-next";

const props = defineProps<{
	show: boolean;
	title: string;
	message: string;
	confirmText?: string;
}>();

const emit = defineEmits<{
	(e: "update:show", value: boolean): void;
	(e: "confirm"): void;
	(e: "cancel"): void;
}>();

function onCancel() {
	emit("cancel");
	emit("update:show", false);
}

function onConfirm() {
	emit("confirm");
}
</script>

<template>
	<Teleport to="body">
		<Transition
			enter-active-class="transition duration-200 ease-out"
			enter-from-class="opacity-0 scale-95"
			enter-to-class="opacity-100 scale-100"
			leave-active-class="transition duration-150 ease-in"
			leave-from-class="opacity-100 scale-100"
			leave-to-class="opacity-0 scale-95"
		>
			<div v-if="show" class="fixed inset-0 z-[100] flex items-center justify-center p-4">
				<div
					class="absolute inset-0 bg-black/40 backdrop-blur-sm"
					@click="onCancel"
				/>
				<div class="relative w-full max-w-[340px] bg-white dark:bg-gray-900 rounded-[1.25rem] shadow-xl p-6 text-center transform transition-all">
					<button
						@click="onCancel"
						class="absolute top-4 right-4 text-gray-400 hover:text-gray-600 dark:hover:text-gray-300"
					>
						<X :size="20" />
					</button>

					<div class="w-16 h-16 rounded-full bg-orange-50 dark:bg-orange-900/20 text-orange-500 mx-auto flex items-center justify-center mb-4">
						<AlertTriangle :size="28" stroke-width="2" />
					</div>

					<h3 class="text-lg font-bold text-gray-900 dark:text-gray-100 mb-2">
						{{ title }}
					</h3>
					
					<p class="text-sm text-gray-500 dark:text-gray-400 mb-6 leading-relaxed whitespace-pre-wrap">{{ message }}</p>

					<div class="flex gap-3">
						<button
							@click="onCancel"
							class="flex-1 py-2.5 rounded-xl bg-gray-50 dark:bg-gray-800 text-gray-700 dark:text-gray-300 font-semibold text-sm hover:bg-gray-100 dark:hover:bg-gray-700 transition"
						>
							{{ __("Cancel") }}
						</button>
						<button
							@click="onConfirm"
							class="flex-1 py-2.5 rounded-xl bg-red-500 text-white font-semibold text-sm hover:bg-red-600 transition"
						>
							{{ confirmText || __("Delete") }}
						</button>
					</div>
				</div>
			</div>
		</Transition>
	</Teleport>
</template>
